```class Solution {
public:
    int maxScore(vector<int>& nums) {
        sort(nums.begin(), nums.end(), greater<int>());
        int res = 0;
        for (int i = 1; i <= nums.size() / 2; ++i) {
            res += i * gcd(nums[2 * i - 2], nums[2 * i - 1]);
        }
        return res;
    }
    int gcd(int x, int y) {
        if (y == 0) return x;
        return gcd(y, x % y);
    }
};
